def srcfn(src):
    "Stores src in linecache under <pyrun_{i%10}>, returns the name." 
    linecache.cache[fn] = (len(src), None,  src.splitlines(keepends=True), fn:=f'<pyrun_{srcfn.i}>')
    srcfn.i = (srcfn.i + 1)%10
    return fn
srcfn.i=0

